xpath.script:

document.addEventListener('DOMContentLoaded', function() {
    const cloudContainer = document.getElementById('cloud-container');
    const rainContainer = document.getElementById('rain-container');
    const isMobile = window.innerWidth <= 768;

    // ===== CLOUD MANAGEMENT =====
    const cloudSizes = ['small', 'medium', 'large', 'xlarge'];
    const clouds = [];
    const maxClouds = isMobile ? 8 : 15;

    // Create initial clouds
    for (let i = 0; i < maxClouds; i++) {
        createCloud(true);
    }

    function createCloud(initial = false) {
        const cloud = document.createElement('div');

        // Random size
        const sizeIndex = Math.floor(Math.random() * cloudSizes.length);
        cloud.className = `cloud cloud-${cloudSizes[sizeIndex]}`;

        // Random vertical position (scattered throughout the sky)
        const top = Math.random() * 80 + 5; // 5% to 85% from top
        cloud.style.top = top + '%';

        // Random horizontal starting position
        // 70% chance to start off-screen on left or right
        let left;
        let direction;

        if (initial) {
            // Initial clouds can be anywhere, including on-screen
            if (Math.random() > 0.3) {
                left = Math.random() * 100; // on-screen
            } else {
                left = -30 + Math.random() * 20; // off-screen left
            }
            direction = Math.random() > 0.5 ? 'right' : 'left';
        } else {
            // New clouds always start off-screen
            if (Math.random() > 0.5) {
                left = -40 + Math.random() * 20; // off-screen left
                direction = 'right';
            } else {
                left = 120 + Math.random() * 20; // off-screen right
                direction = 'left';
            }
        }

        cloud.style.left = left + '%';

        // Random speed - DOUBLED for all sizes
        let speed;
        switch(sizeIndex) {
            case 0: speed = 0.03 + Math.random() * 0.02; break; // small (was 0.015)
            case 1: speed = 0.02 + Math.random() * 0.016; break; // medium (was 0.01)
            case 2: speed = 0.014 + Math.random() * 0.012; break; // large (was 0.007)
            case 3: speed = 0.01 + Math.random() * 0.008; break; // xlarge (was 0.005)
        }

        // Random opacity
        cloud.style.opacity = 0.6 + Math.random() * 0.3;

        cloudContainer.appendChild(cloud);

        // Store cloud data
        clouds.push({
            element: cloud,
            left: left,
            direction: direction || (Math.random() > 0.5 ? 'right' : 'left'),
            speed: speed,
            sizeIndex: sizeIndex
        });
    }

    // ===== RAIN GENERATION =====
    if (rainContainer) {
        rainContainer.innerHTML = '';
        const raindropCount = isMobile ? 150 : 300;

        for (let i = 0; i < raindropCount; i++) {
            const raindrop = document.createElement('div');
            raindrop.className = 'raindrop';

            // Random position
            raindrop.style.left = Math.random() * 100 + '%';
            raindrop.style.top = (Math.random() * 100) + '%';

            // Random animation duration (realistic speed)
            const duration = isMobile ? 1.5 + Math.random() * 1.5 : 2 + Math.random() * 2;
            raindrop.style.animation = `rain ${duration}s linear infinite`;

            // Random delay
            raindrop.style.animationDelay = (Math.random() * 3) + 's';

            // Random size variation
            const height = isMobile ? 12 + Math.random() * 8 : 18 + Math.random() * 12;
            raindrop.style.height = height + 'px';

            rainContainer.appendChild(raindrop);
        }
    }

    // ===== ANIMATION LOOP =====
    function animateClouds() {
        for (let i = clouds.length - 1; i >= 0; i--) {
            const cloud = clouds[i];

            // Move cloud based on direction
            if (cloud.direction === 'right') {
                cloud.left += cloud.speed;
            } else {
                cloud.left -= cloud.speed;
            }

            // Apply position
            cloud.element.style.left = cloud.left + '%';

            // Check if cloud is completely off-screen
            if (cloud.left > 140 || cloud.left < -40) {
                // Remove cloud element
                cloud.element.remove();
                // Remove from array
                clouds.splice(i, 1);
                // Create new cloud to maintain count
                createCloud(false);
            }
        }

        requestAnimationFrame(animateClouds);
    }

    // Start animation
    animateClouds();

    // Handle window resize
    window.addEventListener('resize', function() {
        // Could adjust cloud count based on new screen size
        // For simplicity, we'll just maintain current behavior
    });
});
